use std::sync::{Arc, Mutex, Condvar};
use std::thread;
use std::time::Duration;

struct SignalSystem {
    data: Mutex<bool>,
    condvar: Condvar,
}

impl SignalSystem {
    fn new() -> Self {
        SignalSystem {
            data: Mutex::new(false),
            condvar: Condvar::new(),
        }
    }

    fn wait_for_signal(&self) -> bool {
        let mut guard = self.data.lock().unwrap();
        loop {
            guard = self.condvar.wait(guard).unwrap();
            if *guard == true {
                return true;
            }
        }
    }

    fn send_signal(&self) {
        let mut guard = self.data.lock().unwrap();
        *guard = true;
        self.condvar.notify_one();
    }
}

fn main() {
    let system = Arc::new(SignalSystem::new());

    let waiter = { 
        let s = Arc::clone(&system);
        thread::spawn(move || {
            println!("Waiter thread started, waiting for signal...");
            if s.wait_for_signal() {
                println!("Waiter woke up and successfully processed the data signal!");
            }
        })
    };

    thread::sleep(Duration::from_millis(500));

    println!("Main thread sending the signal now...");
    system.send_signal();

    waiter.join().unwrap();
    println!("Program finished normally.");
}

