use std::sync::{Arc, Mutex, Condvar};
use std::thread;
use std::time::Duration;

struct SignalState {
    ready: bool,
}

fn main() {
    let state = Arc::new(Mutex::new(SignalState { ready: false }));
    let cvar = Arc::new(Condvar::new());
    let state_clone_signal = Arc::clone(&state);
    let cvar_clone_signal = Arc::clone(&cvar);

    let signaling_thread = thread::spawn(move || {
        println!("Signaling thread: Doing some initial work...");
        thread::sleep(Duration::from_secs(2));
        {
            let mut state_guard = state_clone_signal.lock().unwrap();
            state_guard.ready = true;
        }
        cvar_clone_signal.notify_one();
        println!("Signaling thread: Setup complete and signaled.");
    });

    let state_clone_worker = Arc::clone(&state);
    let cvar_clone_worker = Arc::clone(&cvar);

    let worker_thread = thread::spawn(move || {
        println!("Worker thread: Waiting for setup signal...");
        let mut state_guard = state_clone_worker.lock().unwrap();
        while !state_guard.ready {
            state_guard = cvar_clone_worker.wait(state_guard).unwrap();
        }
        drop(state_guard);
        println!("Worker thread: Signal received! Starting port scan simulation.");
        thread::sleep(Duration::from_millis(500));
        println!("Worker thread: Scan finished successfully.");
    });

    signaling_thread.join().unwrap();
    worker_thread.join().unwrap();
}

use std::sync::{Arc, Condvar, Mutex}; use std::thread; use std::time::Duration;

struct MonitorState {
    last_cpu_usage: f32,
    last_memory_bytes: usize,
}

fn main() -> std::io::Result<()> {
    let state = Arc::new(Mutex::new(MonitorState {
        last_cpu_usage: 0.0,
        last_memory_bytes: 0,
    }));
    let cvar = Arc::new(Condvar::new());

    let producer = thread::spawn({
        let state_clone = Arc::clone(&state);
        let cvar_clone = Arc::clone(&cvar);
        move || {
            for i in 0..5 {
                thread::sleep(Duration::from_millis(200));
                { 
                    let mut state_guard = state_clone.lock().unwrap();
                    state_guard.last_cpu_usage = (i as f32) * 10.0;
                    state_guard.last_memory_bytes = 1024 * (i + 1);
                }
                cvar_clone.notify_all();
            }
        }
    });

    let consumer = thread::spawn({
        let state_clone = Arc::clone(&state);
        let cvar_clone = Arc::clone(&cvar);
        move || {
            for _ in 0..5 {
                let mut state_guard = state_clone.lock().unwrap();
                state_guard = cvar_clone.wait(state_guard).unwrap();

                let cpu = state_guard.last_cpu_usage;
                let mem = state_guard.last_memory_bytes;
                println!("Metrics updated: CPU={:.1}, Memory={} (Consumer)", cpu, mem);
            }
        }
    });

    producer.join().ok();
    consumer.join().ok();

    Ok(())
}
